// app/api/og/route.js
import { ImageResponse } from 'next/og';

export const runtime = 'edge';

export async function GET(request) {
  try {
    const { searchParams } = new URL(request.url);

    const title = searchParams.get('title') || 'Boost Your SEO and Daily Productivity with Cutting-Edge AI Tools';
    const category = searchParams.get('category') || 'AI Tools';
    const badge = searchParams.get('badge') || 'NEW!';
    const bgColor = searchParams.get('bgColor') || 'blue';
    const author = searchParams.get('author') || null;
    const readTime = searchParams.get('readTime') || null;
    const ctaText = searchParams.get('ctaText') || 'Start Your AI Journey';
    const featuresParam = searchParams.get('features');
    const features = featuresParam ? featuresParam.split(',').map(f => f.trim()) : ['AI-Powered SEO', '10x Productivity', 'Free Resources'];

    const featureColors = ['#2563eb', '#8b5cf6', '#10b981'];

    const colorSchemes = {
      blue: {
        primary: '#2563eb',
        secondary: '#1d4ed8',
        tertiary: '#1e40af',
        accent: '#3b82f6',
        light: '#60a5fa',
        gradient: 'linear-gradient(135deg, #bfdbfe 0%, #c7d2fe 50%, #ddd6fe 100%)',
      },
      purple: {
        primary: '#8b5cf6',
        secondary: '#7c3aed',
        tertiary: '#6d28d9',
        accent: '#a78bfa',
        light: '#c4b5fd',
        gradient: 'linear-gradient(135deg, #e0e7ff 0%, #ede9fe 50%, #fae8ff 100%)',
      },
      green: {
        primary: '#10b981',
        secondary: '#059669',
        tertiary: '#047857',
        accent: '#34d399',
        light: '#6ee7b7',
        gradient: 'linear-gradient(135deg, #dcfce7 0%, #d1fae5 50%, #a7f3d0 100%)',
      },
      orange: {
        primary: '#f97316',
        secondary: '#ea580c',
        tertiary: '#dc2626',
        accent: '#fb923c',
        light: '#fdba74',
        gradient: 'linear-gradient(135deg, #fed7aa 0%, #fde68a 50%, #fef3c7 100%)',
      },
      teal: {
        primary: '#0d9488',
        secondary: '#0f766e',
        tertiary: '#134e4a',
        accent: '#14b8a6',
        light: '#5eead4',
        gradient: 'linear-gradient(135deg, #ccfbf1 0%, #a7f3d0 50%, #bfdbfe 100%)',
      },
    };

    const currentScheme = colorSchemes[bgColor] || colorSchemes.blue;

    return new ImageResponse(
      (
        <div
          style={{
            height: '100%',
            width: '100%',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            background: currentScheme.gradient,
            position: 'relative',
            overflow: 'hidden',
            fontFamily: 'Inter, system-ui, -apple-system, sans-serif',
          }}
        >
          {/* Simplified AI Background Elements for Performance - Reduced number of elements */}
          <svg width="1200" height="630" viewBox="0 0 1200 630" style={{ position: 'absolute', top: 0, left: 0, opacity: 0.5 }}>
            <defs>
              <linearGradient id="neuralGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor={currentScheme.primary} stopOpacity="0.7" />
                <stop offset="100%" stopColor={currentScheme.accent} stopOpacity="0.4" />
              </linearGradient>
              <linearGradient id="circuitGradient" x1="0%" y1="0%" x2="100%" y2="100%">
                <stop offset="0%" stopColor={currentScheme.primary} stopOpacity="0.6" />
                <stop offset="100%" stopColor="#8b5cf6" stopOpacity="0.4" />
              </linearGradient>
            </defs>
            {/* Reduced nodes for performance */}
            <circle cx="1050" cy="110" r="8" fill={currentScheme.accent} opacity="0.7" />
            <circle cx="200" cy="480" r="8" fill="#8b5cf6" opacity="0.7" />
            <circle cx="600" cy="470" r="8" fill="#10b981" opacity="0.7" />
            <circle cx="1000" cy="480" r="8" fill="#8b5cf6" opacity="0.7" />
            {/* Simplified Circuit Pattern */}
            <rect x="50" y="250" width="200" height="120" rx="15" fill="none" stroke="url(#circuitGradient)" strokeWidth="2" opacity="0.6" />
            <rect x="950" y="280" width="180" height="100" rx="12" fill="none" stroke="url(#circuitGradient)" strokeWidth="2" opacity="0.6" />
            {/* Reduced Data Flow Lines */}
            <path d="M60,280 L240,280" stroke={currentScheme.primary} strokeWidth="2" opacity="0.7" strokeDasharray="5,5" />
            <path d="M60,320 L240,320" stroke={currentScheme.light} strokeWidth="2" opacity="0.7" strokeDasharray="5,5" />
            <path d="M960,310 L1120,310" stroke="#8b5cf6" strokeWidth="2" opacity="0.7" strokeDasharray="5,5" />
            {/* Simplified AI pattern elements */}
            <polygon points="100,350 120,330 140,350 120,370" fill="#10b981" opacity="0.5" />
            <polygon points="1100,200 1120,180 1140,200 1120,220" fill="#8b5cf6" opacity="0.5" />
          </svg>

          {/* Main Content Container - Increased padding for better centering and visibility */}
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              textAlign: 'center',
              padding: '40px',
              zIndex: 10,
              position: 'relative',
              maxWidth: '100%',
            }}
          >
            {/* Logo and Brand Section - Larger for visibility */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '32px' }}>
              {/* Enhanced Logo Placeholder */}
              <div
                style={{
                  width: '112px',
                  height: '112px',
                  borderRadius: '28px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginRight: '32px',
                }}
              >
                <img 
              src="data:image/png;base64," 
              />
 
              </div>
              {/* Brand Name and Badge */}
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <h1
                  style={{
                    fontSize: '84px', // Increased for better visibility
                    fontWeight: '900',
                    background: `linear-gradient(135deg, ${currentScheme.primary}, ${currentScheme.secondary}, ${currentScheme.tertiary})`,
                    backgroundClip: 'text',
                    color: 'transparent',
                    margin: 0,
                    marginRight: '32px',
                    textShadow: '0 6px 12px rgba(0,0,0,0.2)',
                    letterSpacing: '-2.5px',
                    fontFamily: 'Inter, system-ui, sans-serif',
                    lineHeight: '0.9',
                  }}
                >
                  DoItWithAI.tools
                </h1>
                {/* Enhanced Badge */}
                <div
                  style={{
                    background: 'linear-gradient(135deg, #10b981, #059669)',
                    color: 'white',
                    padding: '12px 20px',
                    borderRadius: '28px',
                    fontSize: '18px',
                    fontWeight: '700',
                    textTransform: 'uppercase',
                    boxShadow: '0 6px 24px rgba(16,185,129,0.4)',
                    border: '2px solid rgba(255,255,255,0.3)',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '10px',
                  }}
                >
                  <div style={{ width: '12px', height: '12px', borderRadius: '50%', backgroundColor: '#34d399' }} />
                  {badge}
                </div>
              </div>
            </div>

            {/* Enhanced Main Title - Larger and more prominent */}
            <h2
              style={{
                fontSize: title.length > 50 ? '48px' : '54px', // Increased sizes
                fontWeight: '700',
                color: '#1f2937', // Darker for better contrast
                textAlign: 'center',
                lineHeight: '1.1',
                marginBottom: '24px',
                maxWidth: '1000px',
                textShadow: '0 2px 6px rgba(0,0,0,0.1)',
                letterSpacing: '-1px',
                fontFamily: 'Inter, system-ui, sans-serif',
              }}
            >
              {title}
            </h2>

            {/* Enhanced Key Features - Adjusted for clarity */}
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '28px',
                marginBottom: '32px',
                flexWrap: 'wrap',
              }}
            >
              {features.map((feature, index) => (
                <div key={index} style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <div
                    style={{
                      width: '12px',
                      height: '12px',
                      borderRadius: '50%',
                      background: featureColors[index] || currentScheme.primary,
                      boxShadow: '0 2px 6px rgba(0,0,0,0.15)',
                    }}
                  />
                  <span style={{ color: '#374151', fontSize: '18px', fontWeight: '600' }}>{feature}</span>
                </div>
              ))}
            </div>

            {/* Enhanced Call to Action Button - Larger for emphasis */}
            <div
              style={{
                background: `linear-gradient(135deg, ${currentScheme.primary}, ${currentScheme.secondary})`,
                border: '2px solid rgba(255,255,255,0.3)',
                borderRadius: '24px',
                padding: '18px 36px',
                color: 'white',
                fontSize: '22px',
                fontWeight: 'bold',
                display: 'flex',
                alignItems: 'center',
                gap: '14px',
                backdropFilter: 'blur(12px)',
                boxShadow: '0 8px 32px rgba(0,0,0,0.2)',
              }}
            >
              <div style={{ fontSize: '26px', filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.3))' }}>🚀</div>
              <span>{ctaText}</span>
              <div style={{ fontSize: '22px', transform: 'translateX(2px)' }}>→</div>
            </div>

            {/* Author and Read Time (if provided) - Adjusted position */}
            {(author || readTime) && (
              <div
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '20px',
                  marginTop: '28px',
                  fontSize: '18px',
                  color: '#4b5563',
                }}
              >
                {author && (
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ fontSize: '18px' }}>✍️</div>
                    <span>{author}</span>
                  </div>
                )}
                {author && readTime && (
                  <div style={{ width: '5px', height: '5px', borderRadius: '50%', backgroundColor: '#9ca3af' }} />
                )}
                {readTime && (
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <div style={{ fontSize: '18px' }}>⏱️</div>
                    <span>{readTime} min read</span>
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Enhanced Bottom Brand Watermark - Larger for visibility */}
          <div
            style={{
              position: 'absolute',
              bottom: '28px',
              right: '40px',
              color: '#4b5563',
              fontSize: '18px',
              fontWeight: '600',
              display: 'flex',
              alignItems: 'center',
              gap: '10px',
            }}
          >
            <div
              style={{
                width: '18px',
                height: '18px',
                borderRadius: '20px',
                background: `linear-gradient(135deg, ${currentScheme.primary}, ${currentScheme.secondary})`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                fontSize: '14px',
              }}
            ></div>
            doitwithai.tools
          </div>
        </div>
      ),
      {
        width: 1200,
        height: 630,
        headers: {
          'Cache-Control': 'public, max-age=3600, s-maxage=3600, stale-while-revalidate=86400',
        },
      }
    );
  } catch (e) {
    console.log(`${e.message}`);
    return new Response(`Failed to generate the image`, { status: 500 });
  }
}